const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');

const app = express();
const PORT = process.env.PORT || 3000;

// --- Security middleware ---
app.use(helmet());                          // Sets security headers
app.disable('x-powered-by');                // Remove Express fingerprint

app.use(express.json({ limit: '10kb' }));   // Parse JSON with size limit
app.use(express.urlencoded({ extended: false, limit: '10kb' }));

// Rate limiting — 100 requests per 15 min per IP
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
  message: { error: 'Too many requests, please try again later.' },
});
app.use(limiter);

// --- Routes ---
app.get('/health', (_req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', (req, res) => {
  // Reject unexpected query parameters
  const allowedParams = [];
  const unexpected = Object.keys(req.query).filter(k => !allowedParams.includes(k));
  if (unexpected.length > 0) {
    return res.status(400).json({
      error: 'Bad Request',
      message: `Unexpected query parameter(s): ${unexpected.join(', ')}`,
    });
  }

  res.json([
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob', email: 'bob@example.com' },
  ]);
});

